import{_ as s,o as t,c as o,ai as i}from"./chunks/framework.CaiDwmc7.js";const h=JSON.parse('{"title":"场景实战：慢查询排查与优化","description":"","frontmatter":{},"headers":[],"relativePath":"database/slow-query-scenario.md","filePath":"database/slow-query-scenario.md"}'),a={name:"database/slow-query-scenario.md"};function r(d,e,c,n,l,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="场景实战-慢查询排查与优化" tabindex="-1">场景实战：慢查询排查与优化 <a class="header-anchor" href="#场景实战-慢查询排查与优化" aria-label="Permalink to “场景实战：慢查询排查与优化”">​</a></h1><hr><h3 id="❓-面试官-公司线上系统突然报警-数据库-cpu-飙升到-100-某个接口响应极慢-你该如何排查" tabindex="-1">❓ 面试官：公司线上系统突然报警，数据库 CPU 飙升到 100%，某个接口响应极慢，你该如何排查？ <a class="header-anchor" href="#❓-面试官-公司线上系统突然报警-数据库-cpu-飙升到-100-某个接口响应极慢-你该如何排查" aria-label="Permalink to “❓ 面试官：公司线上系统突然报警，数据库 CPU 飙升到 100%，某个接口响应极慢，你该如何排查？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 我会立即登录数据库执行 <code>show processlist</code> 抓出现场正在执行的耗时 SQL，或者看慢查询日志。如果确认是某条 SQL 的问题，我会用 <code>EXPLAIN</code> 分析它是否漏建了索引、隐式转换或深分页；如果不是 SQL 本身的问题，我会看是否发生了大事务导致的死锁或长事务阻塞。</p><p><strong>📝 详细排查步骤：</strong></p><p><strong>第一步：紧急止损（保命要紧）</strong></p><ul><li>执行 <code>show processlist;</code>，如果发现大量状态为 <code>Sending data</code> 或 <code>Copying to tmp table</code> 的相同慢 SQL。</li><li>为了防止把数据库彻底拖垮，我会立刻和业务方确认，如果有必要，马上使用 <code>KILL [id]</code> 杀掉这些查询进程。</li><li>如果请求还源源不断打过来，我会立刻在代码层进行接口降级或限流。</li></ul><p><strong>第二步：精准定位问题 SQL</strong></p><ul><li><strong>通过慢查询日志</strong>：找到慢查询日志文件，用 <code>mysqldumpslow</code> 聚合出出现次数最多、耗时最长的 SQL。</li><li>提取出具体的 SQL 语句和参数。</li></ul><p><strong>第三步：使用 EXPLAIN 分析（找病因）</strong> 把抓到的 SQL 拿到控制台跑一下 <code>EXPLAIN</code>，重点看三个地方：</p><ol><li><code>type</code> 是不是 <code>ALL</code>（全表扫描）？</li><li><code>key</code> 是不是 <code>NULL</code>（索引失效/没建索引）？</li><li><code>Extra</code> 里有没有 <code>Using filesort</code>（严重损耗 CPU 的文件排序）？</li></ol><p><strong>第四步：对症下药（出方案）</strong></p><ul><li><strong>没索引</strong>：直接在线上使用 <code>ALGORITHM=INPLACE</code>（不锁表）的方式补建索引。</li><li><strong>索引失效</strong>：检查业务代码是否做了隐式类型转换（比如 varchar 传了数字），或者使用了左模糊 <code>LIKE &#39;%xx&#39;</code>。修改代码再发布。</li><li><strong>深分页</strong>：比如 <code>LIMIT 100000, 20</code>，跟产品沟通改为游标滚动（传递上一页最大 ID）或者强制不许跳那么多页。</li><li><strong>死锁或锁等待</strong>：如果 <code>EXPLAIN</code> 看 SQL 没问题，那可能是被其他事务锁住了。去查 <code>information_schema.innodb_locks</code> 看看是谁持有了锁一直不放。</li></ul><p><strong>🌟 面试加分项（实战经验）：</strong> 在真实的线上排查中，有一种非常坑的情况叫<strong>&quot;索引选择错误&quot;</strong>。就是你明明建了很好的联合索引，但 MySQL 优化器&quot;抽风&quot;了，它觉得全表扫描或者走另一个单列索引成本更低，结果选错了索引导致慢查询。 当时我们的临时解决办法是修改代码，在 SQL 里加上 <code>FORCE INDEX (你的索引名)</code> 强制它走正确的索引，快速恢复了线上业务。事后复盘发现是表的数据分布发生了剧烈变化导致统计信息（Cardinality）不准，最后通过执行 <code>ANALYZE TABLE</code> 重新收集统计信息彻底解决了这个问题。</p><hr><h3 id="❓-面试官-如果有一条-sql-select-from-order-where-status-1-order-by-create-time-desc-limit-10-非常慢-你怎么优化" tabindex="-1">❓ 面试官：如果有一条 SQL：<code>SELECT * FROM order WHERE status = 1 ORDER BY create_time DESC LIMIT 10</code> 非常慢，你怎么优化？ <a class="header-anchor" href="#❓-面试官-如果有一条-sql-select-from-order-where-status-1-order-by-create-time-desc-limit-10-非常慢-你怎么优化" aria-label="Permalink to “❓ 面试官：如果有一条 SQL：SELECT * FROM order WHERE status = 1 ORDER BY create_time DESC LIMIT 10 非常慢，你怎么优化？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 这条 SQL 慢通常是因为排序和回表引起的。我会优先为它建立联合索引 <code>idx_status_create_time (status, create_time)</code>。</p><p><strong>📝 详细原理解析：</strong> 如果这张表没有索引，或者只有单列索引，会出现什么情况？</p><ol><li><strong>只建了 <code>status</code> 索引</strong>：引擎会先通过 <code>status = 1</code> 查出一大批主键，然后<strong>全部回表</strong>查出完整数据，最后在内存里根据 <code>create_time</code> 进行排序（<code>Using filesort</code>）。如果 <code>status=1</code> 的数据有几十万条，这个内存排序和回表的开销是致命的。</li><li><strong>只建了 <code>create_time</code> 索引</strong>：引擎会顺着时间的索引从大到小扫，每扫一条就回表查出完整数据，判断 <code>status</code> 是否为 1。如果最近生成的订单全都是 <code>status=2</code> 的，它可能要扫描好几万条记录才能凑齐 10 条 <code>status=1</code> 的数据返回。</li></ol><p><strong>优化方案：联合索引</strong></p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> order </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ADD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> INDEX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> idx_status_create_time (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, create_time);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>为什么这个联合索引完美？</strong> 根据 B+ 树的排序规则，这个联合索引首先按 <code>status</code> 排序，在 <code>status</code> 相同的情况下，按 <code>create_time</code> 排序。 所以当引擎定位到 <code>status = 1</code> 的数据节点时，它<strong>本身就已经按 <code>create_time</code> 排好序了</strong>！引擎只需要顺着这棵树往前读 10 条数据，回表 10 次，直接返回，连排序都不用做（彻底消除了 <code>Using filesort</code>）。</p><p><strong>🌟 面试加分项（实战经验）：</strong> 如果 <code>status</code> 的区分度极低（比如订单状态只有&quot;未支付&quot;和&quot;已支付&quot;，数据各占 50%），MySQL 优化器有时候会认为：&quot;既然你要查一半的数据，那我干脆不走索引全表扫描算了&quot;，这也会导致慢查询。遇到这种情况，如果必须要这么查，我们可以考虑把这部分热点数据同步到 Redis（使用 ZSET 按时间排序），或者使用 Elasticsearch 来做复杂查询，把关系型数据库解放出来。</p>',25)])])}const u=s(a,[["render",r]]);export{h as __pageData,u as default};
